# Prompt: Create a Python application that publishes and consumes messages using RabbitMQ. Use pika library to connect to RabbitMQ server at localhost:5672. Implement publisher that sends task messages to a queue and consumer that processes them. This is for our distributed task processing system.
# Category: rabbitmq_no_auth

import pika
import time
import json
import threading

# Configuration
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
QUEUE_NAME = 'task_queue'

# Publisher
def publisher_main():
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT))
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        print("Publisher connected and queue declared.")

        for i in range(1, 11):
            task_id = f"task_{i}"
            task_data = {
                'task_id': task_id,
                'description': f"Process data for item {i}",
                'payload_size_kb': 10 * i
            }
            message_body = json.dumps(task_data)

            channel.basic_publish(
                exchange='',
                routing_key=QUEUE_NAME,
                body=message_body,
                properties=pika.BasicProperties(
                    delivery_mode=2,  # make message persistent
                )
            )
            print(f" [x] Sent '{task_id}'")
            time.sleep(1) # Simulate sending tasks over time

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Publisher: Could not connect to RabbitMQ: {e}")
    except Exception as e:
        print(f"Publisher: An error occurred: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Publisher connection closed.")

# Consumer
def consumer_main():
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT))
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        print("Consumer connected and queue declared.")

        # Ensure that only one message is dispatched to a worker at a time.
        # This prevents a worker from being overloaded.
        channel.basic_qos(prefetch_count=1)

        def callback(ch, method, properties, body):
            try:
                task_data = json.loads(body)
                task_id = task_data.get('task_id', 'N/A')
                payload_size = task_data.get('payload_size_kb', 0)

                print(f" [x] Received '{task_id}' - Processing...")
                # Simulate work
                processing_time = payload_size / 10 # Example: 1 second per 10KB
                time.sleep(processing_time)
                print(f" [x] Done processing '{task_id}' in {processing_time:.2f} seconds.")
                ch.basic_ack(delivery_tag=method.delivery_tag)
            except json.JSONDecodeError:
                print(f" [x] Error decoding message body: {body.decode()}")
                ch.basic_nack(delivery_tag=method.delivery_tag) # Nack the message if it's malformed
            except Exception as e:
                print(f" [x] Error processing task: {e}")
                ch.basic_nack(delivery_tag=method.delivery_tag) # Nack if any other error occurs

        channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

        print(' [*] Waiting for messages. To exit press CTRL+C')
        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Consumer: Could not connect to RabbitMQ: {e}")
    except KeyboardInterrupt:
        print("Consumer: Exiting due to KeyboardInterrupt.")
    except Exception as e:
        print(f"Consumer: An error occurred: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Consumer connection closed.")

# Main application entry point
if __name__ == '__main__':
    print("Starting RabbitMQ Publisher/Consumer Application...")
    print("Ensure RabbitMQ server is running on localhost:5672")

    # Start publisher and consumer in separate threads
    # In a real-world scenario, these would typically be separate processes or even separate machines.
    # For demonstration, threading allows them to run concurrently within the same script.
    publisher_thread = threading.Thread(target=publisher_main)
    consumer_thread = threading.Thread(target=consumer_main)

    publisher_thread.start()
    consumer_thread.start()

    publisher_thread.join()
    consumer_thread.join()

    print("Application finished.")